const t={name:"Plommon",icon:"plommon",category:"frukt",family:"Rosväxter",familyLatin:"Rosaceae",perennial:!0,lifespan:"40-60 år",difficulty:"Medel",difficultyWhy:"Kräver årlig beskärning (OBS: bara sommarhalvåret!), viss sjukdomskontroll och tålamod de första åren. Men de flesta svenska plommonsorter är självfertila och ger riklig skörd - det är ett tacksamt fruktträd.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:null},days:"Skörd år 3-5",spacing:"3-5 m",spacingNote:"Beroende på grundstam: Pixy (dvärg) 2,5-3 m, St. Julien 3-4 m, fröstam 4-5 m",rowSpacing:"4-6 m",depth:"Ympstället 10 cm ovan mark",depthNote:"Samma princip som äpple och päron - ympstället ska synas ovanför jorden",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmars direkt sol. Plommon behöver sol och värme för att mogna ordentligt - i halvskugga blir frukten sur och liten. En sydvänd mur eller häck i ryggen gör underverk."},temperature:{min:-25,max:35,ideal:"18-25°C",detail:"De flesta europeiska plommonsorter tål -25°C i vila. Men sena vårfroster är den stora fienden - plommonblomningen är ömtålig. Välj en plats som inte är en frostficka."},wind:{level:"Skyddat",detail:"Vindskydd förbättrar pollinering och minskar fruktfall. Plommonträd med tung skörd kan tappa grenar i blåst - stötta tunga grenar med grenspjut."}},watering:{need:"Medel",icon:"water",summary:"Etablerade plommonträd klarar sig relativt bra på regnvatten. Nyplanterade träd behöver vattning, och under torra somrar kan extra vatten ge avsevärt bättre skörd.",phases:[{phase:"Vår (blomning)",need:"Medel",tip:"Vattna vid torka under blomning - vattenstress ger sämre fruktsättning."},{phase:"Sommar (fruktutveckling)",need:"Medel-Hög",tip:"Vattna jämnt under frukttillväxten. Ojämn vattning kan ge sprickbildning i frukten - ett vanligt problem med plommon."},{phase:"Mognad (jul-sep)",need:"Medel",tip:"Minska vattningen mot mognad. Lite torrare förhållanden ger sötare frukt med bättre arom."},{phase:"Vinter",need:"Ingen",tip:"Trädet vilar. Minska vattning redan från mitten av augusti."}],mistakes:["Glömmer att vattna nyplanterade träd första somrarna","Ojämn vattning under fruktutveckling - plommon spricker lätt","Vattnar för sent på hösten - stimulerar tillväxt som inte hinner mogna"],tip:"Mulcha med gräsklipp (max 10 cm tjockt) runt trädet men inte intill stammen. Sluta mulcha efter juli - trädet ska förbereda sig för vinter, inte fortsätta växa."},soil:"Väldränerad, näringsrik, mullrik jord. Plommon trivs bäst i lagom tung lerjord med god dränering. Tung, vattenmättad lera är den vanligaste orsaken till att plommonträd mår dåligt.",soilTips:["Gräv en grop dubbelt så bred som rotklumpen","Blanda in kompost i uppgrävd jord (max 1/3)","På tung lera: plantera i upphöjd bädd (ca 30 cm) för bättre dränering","Undvik frostfickor - välj en sluttning eller plats nära hus"],timeline:{1:[{phase:"Sommarbeskärning (JAS)",months:"Jul-aug",icon:"scissors"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Fruktgallring",months:"Juni-juli",icon:"growth"},{phase:"Fruktmognad",months:"Jul-sep",icon:"harvest"},{phase:"Höstplantering",months:"Sep-okt",icon:"seedling"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}],4:[{phase:"Sommarbeskärning (JAS)",months:"Jul-aug",icon:"scissors"},{phase:"Blomning",months:"Maj-juni",icon:"bloom"},{phase:"Fruktgallring",months:"Juli",icon:"growth"},{phase:"Fruktmognad",months:"Aug-sep",icon:"harvest"},{phase:"Höstplantering",months:"Sep-okt",icon:"seedling"},{phase:"Vintervila",months:"Nov-mars",icon:"snowflake"}],6:[{phase:"Sommarbeskärning (JAS)",months:"Jul-aug",icon:"scissors"},{phase:"Blomning",months:"Maj",icon:"bloom"},{phase:"Fruktgallring",months:"Juni-juli",icon:"growth"},{phase:"Fruktmognad",months:"Aug-sep",icon:"harvest"},{phase:"Höstplantering",months:"Okt",icon:"seedling"},{phase:"Vintervila",months:"Nov-feb",icon:"snowflake"}]},nutritionData:[{month:"Mar",N:2,P:1,K:1},{month:"Apr",N:5,P:3,K:2},{month:"Maj",N:7,P:5,K:4,label:"Blomning"},{month:"Jun",N:8,P:6,K:5,label:"Fruktsättning"},{month:"Jul",N:5,P:5,K:7,label:"Mognad börjar"},{month:"Aug",N:3,P:3,K:8,label:"Skörd"},{month:"Sep",N:1,P:2,K:4}],nutritionTips:[{timing:"Tidig vår (mars-april)",tip:"Ge kompost eller brunnen naturgödsel runt droppzonen. Undvik för mycket kväve - det ökar risken för sjukdomar och ger frodiga blad men dålig frukt."},{timing:"Blomning (maj)",tip:"En liten giva vedaska (kaliumrik) stärker blomning och fruktsättning."},{timing:"Sommar",tip:"Ingen extra gödsling behövs. Mulcha med gräsklipp för långsam näringstillförsel."},{timing:"Höst",tip:"Mulcha med löv eller kompost. Ingen kvävegödsling efter midsommar - nya skott måste mogna före vintern."}],companions:{good:[{name:"Ringblomma",icon:"flower",why:"Avskräcker bladlöss och lockar nyttoinsekter som pollinerar blommorna."},{name:"Klöver",icon:"flower",why:"Fixerar kväve, täcker marken och lockar humlor. Bra marktäckare under fruktträd."},{id:"graslok",name:"Gräslök",icon:"herb",why:"Traditionellt planterad runt fruktträd - kan motverka svampsjukdomar."},{name:"Lavendel",icon:"flower",why:"Lockar pollinatörer med sin starka doft och avskräcker vissa skadedjur."}],bad:[{id:"potatis",name:"Potatis",icon:"vegetable",why:"Ökar risken för rotröta (Phytophthora) som kan skada trädets rötter."},{name:"Gräsmatta ända in",icon:"grass",why:"Gräs konkurrerar hårt om vatten och näring i rotzonen. Håll en ogräsfri cirkel (1 m radie) runt stammen."}]},rotation:{avoid:[{name:"Plommon"},{name:"Körsbär"},{name:"Äpple"},{name:"Päron"}],avoidWhy:"Plantera aldrig ett nytt plommonträd exakt där ett gammalt stått - sjukdomsorganismer i jorden (trötthetssjuka) gör att det nya trädet aldrig riktigt trivs. Vänta minst 5 år eller välj en annan plats.",goodBefore:[{name:"Gräsmatta"},{name:"Gröngödsling"}],goodBeforeWhy:"Mark som legat som gräsmatta eller gröngödslats ger bäst förutsättningar.",goodAfter:[{name:"Gröngödsling"},{name:"Baljväxter"}],goodAfterWhy:"Gröngödsla i minst 3-5 år efter att ett gammalt fruktträd tagits bort."},varieties:[{name:"Herman",zones:[1,2,3,4],note:'Tidigast av alla (slutet juli). Blålila, sötsyrlig, fast kött. Självfertil. Grönt kulturarv. "Sommarstugeägarens favorit" - hinner mogna före semesterns slut.'},{name:"Opal",zones:[1,2,3,4],note:"Tidig (aug). Rödviolett med grådagg, aromatisk och sötsyrlig. Självfertil. Grönt kulturarv (Balsgård). Sveriges mest populära plommonsort."},{name:"Victoria",zones:[1,2,3,4],note:"Sen (sept). Gulröd med violett dagg, söt, saftig. Självfertil. Grönt kulturarv. Sveriges mest odlade plommonsort. Otroligt produktiv - stötta grenarna!"},{name:"Jubileum",zones:[1,2,3,4],note:"Tidig höst (sept). Purpurfärgad, större och godare än Victoria. Svensk sort från Balsgård 1988. Självfertil. Grönt kulturarv. Ses som Victorias ersättare."},{name:"Reine Claude d'Oullins",zones:[1,2,3,4],note:"Sen sommar (aug-sept). Stor, rund, gulgrön med smältande sött kött. Självfertil. Grönt kulturarv. Anses av många som det godaste plommonet."},{name:"Czar",zones:[1,2,3,4,5],note:"Sen sommar (aug). Blå, oval, saftig. Självfertil. Gammal sort (1800-tal). Det härdigaste plommonet - fungerar upp till zon 5. Svagväxande, litet träd."},{name:"Violetta",zones:[1,2,3],note:"Mitten aug. Mörkviolett, söt, fin arom. Korsning Grand Duke x Herman. Självfertil. Grönt kulturarv. Litet träd med vacker blomning."},{name:"Experimentalfältsviskon",zones:[1,2,3,4],note:"Sent (mitten sept). Mörkviolett, liten, aromatisk. Svenskt kulturarv från Experimentalfältet i Stockholm. Självfertil. Kraftigt växande."},{name:"Stor Grön Reine Claude",zones:[1,2,3,4],note:"Höst (sept). Gröngrå, smältande sött kött med exceptionell arom. Kom till Sverige på 1700-talet. Kulturarvssort. Delvis självfertil - bättre med pollinator."},{name:"Excalibur",zones:[1,2,3],note:"Sen sommar (aug-sept). Rödviolett, välsmakande. Engelsk sort. INTE självfertil - behöver Opal eller Victoria som partner."}],problems:[{name:"Pungsjuka (Taphrina pruni)",symptom:'Frukterna deformeras till avlånga, tomma "pungplommon" utan kärna. Gulgröna, svampiga frukter. Vanligast vid kall, fuktig vår.',fix:"Plocka bort angripna frukter INNAN svampen hinner sprida sporer. Ingen kemisk bekämpning. Reine Claude d'Oullins, Opal och Victoria är motståndskraftiga."},{name:"Monilia (fruktröta/blomtorka)",symptom:"Blommor vissnar och hänger kvar, grenar dör. På frukt: brun röta med vita/gråa sporcirklar. Fruktmumier hänger kvar i trädet.",fix:"Ta bort alla fruktmumier (de sprider smitta!). Samla fallfrukt. Beskär angripna grenar in till frisk ved. God luftcirkulation och undvik övergödsling med kväve."},{name:"Plommonvecklare (Cydia funebrana)",symptom:'"Mask i plommonet" - larver äter sig in i frukten. Angripna plommon faller i förtid. Liten ljusbrun fjäril (1 cm vingspann).',fix:"Häng feromonfällor i trädet strax efter blomning. Plocka och kassera angripna frukter tidigt. Biologisk bekämpning med Bacillus thuringiensis (Bt)."},{name:"Gummiflöde (Gummosis)",symptom:'Trädet "blöder" klart, klibbigt harts/gummi från snittytor eller skador. Vanligt efter felbeskärning.',fix:"Beskär ALDRIG plommon på vintern! JAS-perioden (juli-aug-sept) är enda rätta tiden. Skydda mot barkskador. Rena, vassa verktyg minskar risken."}],pollination:{selfFertile:!0,description:"De flesta svenska plommonsorter (Herman, Opal, Victoria, Jubileum, Reine Claude d'Oullins, Czar) är självfertila - de kan sätta frukt ensamma. MEN: korspollinering ger alltid större, fler och bättre frukter. Har du plats, plantera gärna två sorter.",groups:[{name:"Tidig blomning",varieties:["Herman","Opal","Czar"]},{name:"Mellanblommande",varieties:["Victoria","Jubileum","Reine Claude d'Oullins","Excalibur"]},{name:"Sen blomning",varieties:["Experimentalfältsviskon","Stor Grön Reine Claude"]}],tip:"De flesta sorter är självfertila, men två träd ger alltid bättre skörd. Opal och Victoria är utmärkta universalpollinatörer som passar de flesta. OBS: europeiska plommon (Prunus domestica) och japanska plommon (P. salicina) kan INTE pollinera varandra."},establishment:{description:"Plommonträd etablerar sig snabbare än äpple och päron - särskilt på dvärggrundstam (Pixy) kan du få frukt redan år 2-3. Men de första åren avgör trädets hela framtid.",years:[{year:"År 1",tasks:["Vattna en hink per vecka hela första sommaren","Plocka bort ALL frukt - trädet ska bygga rötter","Kontrollera stödbindningen","Mulcha i 1 meters radie (inte intill stammen)","Ta bort rotskott tidigt - riv helst loss för hand"]},{year:"År 2",tasks:["Planteringsbeskärning: spara 3-4 huvudgrenar, korta in till ca 30 cm","Tillåt max 5-10 frukter","Fortsätt ta bort rotskott","Gödsla försiktigt med kompost"]},{year:"År 3-5",tasks:["Årlig sommarbeskärning (JAS) - aldrig vinter!","Öka tillåtna frukter gradvis","Fruktgallring: lämna 4-5 cm mellan frukter","Stötta tunga grenar med grenspjut (särskilt Victoria)"]}],protection:["Stamskydd mot gnagare (nät eller spiral) - kaniner och sorkar gnager bark","Viltskydd om rådjur finns i området","Stammskydd mot solbränna på sydvästra sidan vintertid","Stötta tunga grenar - plommonträd med rik skörd kan tappa grenar"],tip:"Plommonträd bildar ofta rotskott - särskilt om rötterna skadas av gräsklippare eller spade. Ta bort dem tidigt, helst genom att riva loss dem för hand (sekatör stimulerar fler skott)."},ripeningGuide:{description:"Plommon mognar från slutet av juli till oktober beroende på sort. Till skillnad från päron ska plommon mogna på trädet - plocka dem när de är mjuka, aromatiska och lossnar lätt. Ett plommon som mognat klart på trädet har en helt annan smak än ett butiksplockat.",entries:[{variety:"Herman",from:"jul",to:"aug",type:"Tidigt plommon"},{variety:"Opal",from:"aug",to:"aug",type:"Tidigt plommon"},{variety:"Violetta",from:"aug",to:"aug",type:"Sommarplommon"},{variety:"Czar",from:"aug",to:"aug",type:"Sommarplommon"},{variety:"Reine Claude d'Oullins",from:"aug",to:"sep",type:"Sommarplommon"},{variety:"Excalibur",from:"aug",to:"sep",type:"Sommarplommon"},{variety:"Jubileum",from:"sep",to:"sep",type:"Höstplommon"},{variety:"Victoria",from:"sep",to:"sep",type:"Höstplommon"},{variety:"Stor Grön Reine Claude",from:"sep",to:"sep",type:"Höstplommon"},{variety:"Experimentalfältsviskon",from:"sep",to:"sep",type:"Sent plommon"}],tip:"Bästa testet: ta försiktigt i plommonet. Ger det efter lite och doftar sött? Då är det dags. Plommon som plockats för tidigt blir aldrig riktigt goda - de mognar inte efter som päron gör."},goodToKnow:[{icon:"warning",title:"Beskär ALDRIG plommon på vintern!",text:'Detta är den viktigaste regeln för plommon: beskär BARA under JAS-perioden (juli, augusti, september). Vinterbeskärning ger gummiflöde - trädet "blöder" klart, klibbigt harts från snitten. Snitten läker dåligt och svampinfektioner tar sig in.',severity:"warning"},{icon:"warning",title:"Stötta tunga grenar",text:"Plommonträd - särskilt Victoria - kan ge så riklig skörd att grenarna knäcks. Stötta tunga grenar med grenspjut eller Y-formade pinnar. Bättre att förebygga än att förlora en huvudgren.",severity:"warning"},{icon:"tip",title:"Självfertilt = du kan nöja dig med ETT träd",text:"De flesta svenska plommonsorter (Herman, Opal, Victoria, Jubileum, Reine Claude d'Oullins, Czar) är självfertila. Du kan alltså plantera bara ett enda träd och ändå få skörd. Men två sorter ger alltid bättre resultat.",severity:"tip"},{icon:"tip",title:"Rotskott - ta bort dem!",text:"Plommonträd bildar ofta rotskott som dyker upp runt trädet. De suger energi och ger aldrig bra frukt (de kommer från grundstammen). Ta bort dem genom att riva loss dem för hand tidigt på säsongen.",severity:"tip"},{icon:"tip",title:"Torka till katrinplommon",text:"Har du överskott? Halvera, kärna ur och torka i ugn (50°C, 8 timmar) eller frukttork. Hemgjorda katrinplommon/sviskon är på en helt annan nivå än köpepåsen. Perfekt vintersnacks.",severity:"tip"}],sowing:{method:"direct",label:"Plantering",description:"Plommonträd planteras som ympade träd. Plantera gärna på sensommaren eller tidig höst för optimal etablering. Krukodlade kan planteras hela säsongen.",steps:["Gräv en grop dubbelt så bred som rotsystemet men lika djup","Slå ner en stödpåle INNAN du sätter trädet","Sätt trädet med ympstället 10 cm ovan mark","Fyll igen med uppgrävd jord blandat med kompost","Packa jorden försiktigt runt rötterna","Vattna rikligt - minst 20-30 liter","Bind stammen löst mot stödpålen","Mulcha en cirkel på 1 meters radie (inte intill stammen)"],tips:["Sensommar/höstplantering ger bäst etablering","St. Julien INRA är den vanligaste grundstammen för hobbyodlare - bra balans mellan storlek och härdighet","De flesta sorter är självfertila, men två sorter ger alltid bättre skörd","Välj plats utan frostficka - plommonblomning är ömtålig"],indoorWeeks:null},seedSaving:{difficulty:"Avancerad",type:"Ympning",biennial:!1,description:"Plommonträd förökas genom ympning på grundstam. Att så kärnor ger nya, unika träd med okända egenskaper - spännande experiment men ingen garanti för god frukt.",steps:["Samla ympkvistar i jan-feb (vilande, ettåriga skott)","Förvara i fuktig tidning i kylskåp till april","Välj grundstam (St. Julien INRA för medelstor, Pixy för dvärg)","Utför kopulationsympning eller ögonympning","Skydda ympstället med ympvax","Vänta 2-4 år på första skörd (snabbare än äpple/päron)"],isolation:"Ympning klonar sorten exakt - ingen korspollinering relevant.",storageYears:"Ympkvistar håller 2-3 månader i kylskåp",tip:"Plommon är enklare att ympa än äpple. Går du en ympkurs på våren kan du ofta ta med dig ympkvistar av kulturarvssorter som Experimentalfältsviskon och Ive hem."},storage:{shelfLife:"1 vecka (färsk) / 6+ mån (torkad/sylt)",methods:[{method:"Kylskåp (färsk)",icon:"snowflake",duration:"5-7 dagar",description:"Lägg plommon i grönsakslådan. Kort hållbarhet - svenska plommon har mjukt kött och skört skal. Ät dem snart!",best:!0},{method:"Torkning (katrinplommon)",icon:"sun",duration:"6+ månader",description:"Halvera, kärna ur och torka i ugn på 50°C i ca 8 timmar eller i frukttork. Hemgjorda katrinplommon/sviskon är fantastiskt goda.",best:!1},{method:"Sylt",icon:"storage",duration:"1+ år",description:"Koka plommonsylt med socker och citronjuice. Fyll på steriliserade burkar. En klassiker som fångar smaken av sensommaren.",best:!1},{method:"Frysning",icon:"snowflake",duration:"8-12 månader",description:"Halvera, kärna ur och frys i påsar. Fryses hela med kärna också, men halverade tinar bättre. Perfekt till pajer och smoothies.",best:!1},{method:"Saft",icon:"storage",duration:"6+ månader",description:"Koka sönder i saftsil, tillsätt socker. Plommonsaft är underbart och en bortglömd svensk klassiker.",best:!1}],tips:["Plommon har kort hållbarhet - planera vad du ska göra med skörden INNAN den kommer","Skörda på morgonen för bäst hållbarhet","Tunnväggiga sorter (Herman) håller sämre än tjockväggiga (Victoria)","Mogen frukt med vaxdagg intakt håller bäst - tvätta inte förrän du ska äta"]},harvestCalc:{minPerSqm:3,maxPerSqm:10,unit:"kg per träd (år 5+)"},pruning:{label:"Beskärning",types:{summer:{name:"JAS-beskärning (huvudbeskärning)",when:"Juli-augusti-september (ALDRIG vinter!)",description:'Plommon är "blödande växtslag" - snitt på vintern ger gummiflöde (klart harts som läcker ur snitten). Därför beskärs plommon BARA under JAS-perioden. Snitt som görs på sommaren läker snabbt och risken för svampinfektion är minimal.',steps:["Ta bort döda, sjuka och korsande grenar","Nyp av mjuka vattenskott (sommarpincering)","Glesa ur kronan för ljus och luftcirkulation","Ta bort rotskott - riv helst loss för hand","Stötta tunga grenar med grenspjut vid rik skörd","Rena, vassa verktyg - desinficera vid sjukdomsmisstanke"]},winter:{name:"Planteringsbeskärning (undantag)",when:"Vid plantering (vår)",description:"Det enda tillfället du beskär plommon utanför JAS: vid plantering. Spara 3-4 huvudgrenar och en toppskottsledare. Korta in till ca 30 cm. Detta balanserar rot och krona.",steps:["Välj 3-4 jämnt fördelade huvudgrenar","Korta in till ca 30 cm","Ta bort svaga och korsande grenar","Gör detta bara vid planteringstillfället"]}}},propagation:{difficulty:"Avancerad",methods:[{method:"Ympning",description:"En kvist från önskad sort fästs på en utvald grundstam (St. Julien INRA vanligast). Kopulationsympning på våren eller ögonympning i augusti. Plommon är enklare att ympa än äpple.",icon:"seedling"},{method:"Frösådd (experiment)",description:"Stratifiera kärnor i kylskåp 8-12 veckor, så i kruka. Ger ett unikt träd med okända egenskaper. Snabbare till skörd än äpple/päron (5-8 år). Spännande men oförutsägbart!",icon:"seed"}],tip:"Plommon ympar sig oväntat lätt jämfört med äpple. Ympkurser arrangeras av trädgårdsföreningar varje vår - ofta kan du få med dig ympkvistar av gamla kulturarvssorter hem."}};export{t as plommon};
